UserAuthenticator service handles user login and session management. This is a frequently accessed component that validates credentials and issues JWT tokens.

pub struct UserAuthenticator {
    jwt_secret: String,
    token_ttl: Duration,
}

impl UserAuthenticator {
    pub async fn authenticate(&self, username: &str, password: &str) -> Result<Token> {
        let user = self.validate_credentials(username, password).await?;
        self.issue_token(&user)
    }
}

CacheLayer provides fast in-memory caching with LRU eviction. This is a hot path component used by many services for performance optimization.

pub struct CacheLayer<K, V> {
    store: LruCache<K, V>,
    ttl: Duration,
    hits: AtomicU64,
    misses: AtomicU64,
}

impl<K: Hash + Eq, V: Clone> CacheLayer<K, V> {
    pub fn get(&self, key: &K) -> Option<V> {
        self.store.get(key).cloned()
    }
}

DatabaseConnectionPool manages database connections efficiently. This component is accessed on every database query making it a hot path.

pub struct DatabaseConnectionPool {
    connections: Vec<Connection>,
    available: Semaphore,
    max_size: usize,
}

impl DatabaseConnectionPool {
    pub async fn acquire(&self) -> PooledConnection {
        self.available.acquire().await;
        self.connections.pop().expect("connection available")
    }
}

RequestRouter dispatches incoming HTTP requests to handlers. This is the entry point for all API calls, making it extremely frequently accessed.

struct RequestRouter {
    routes: HashMap<String, Handler>,
    middleware: Vec<Middleware>,
}

impl RequestRouter {
    async fn route(&self, req: Request) -> Response {
        let handler = self.routes.get(&req.path)?;
        self.run_middleware(req, handler).await
    }
}

MetricsCollector aggregates application metrics for monitoring. Accessed on every request to track latency and error rates.

pub struct MetricsCollector {
    counters: HashMap<String, AtomicU64>,
    histograms: HashMap<String, Histogram>,
}

impl MetricsCollector {
    pub fn record_latency(&self, endpoint: &str, latency_ms: u64) {
        if let Some(h) = self.histograms.get(endpoint) {
            h.record(latency_ms);
        }
    }
}

SessionStore manages user sessions with Redis backend. Critical for maintaining user state across requests.

pub struct SessionStore {
    redis: RedisClient,
    prefix: String,
    ttl: Duration,
}

impl SessionStore {
    pub async fn get_session(&self, session_id: &str) -> Option<Session> {
        let key = format!("{}{}", self.prefix, session_id);
        self.redis.get(&key).await.ok()
    }
}

ConfigLoader reads application configuration at startup and caches it. Accessed frequently for feature flags and settings.

struct ConfigLoader {
    config: Arc<RwLock<Config>>,
    path: PathBuf,
}

impl ConfigLoader {
    fn get(&self, key: &str) -> Option<String> {
        self.config.read().get(key).cloned()
    }
}

RateLimiter controls API request rates per client. Consulted on every incoming request to prevent abuse.

pub struct RateLimiter {
    limits: HashMap<String, u64>,
    window: Duration,
    store: RedisClient,
}

impl RateLimiter {
    pub async fn check(&self, client_id: &str) -> Result<(), RateLimitError> {
        let count = self.store.incr(&format!("rate:{}", client_id)).await?;
        if count > self.limits.get(client_id).unwrap_or(&100) {
            Err(RateLimitError::Exceeded)
        } else {
            Ok(())
        }
    }
}

LogFormatter structures log messages for output. Used by every logging call in the application.

pub struct LogFormatter {
    format: LogFormat,
    include_timestamp: bool,
}

impl LogFormatter {
    pub fn format(&self, record: &LogRecord) -> String {
        match self.format {
            LogFormat::Json => serde_json::to_string(record).unwrap(),
            LogFormat::Text => format!("{} [{}] {}", record.timestamp, record.level, record.message)
        }
    }
}

ErrorHandler provides centralized error handling and response formatting. Called for every error in the application.

pub struct ErrorHandler {
    include_stack_trace: bool,
    notify_on_error: bool,
}

impl ErrorHandler {
    pub fn handle(&self, err: AppError) -> Response {
        let status = err.status_code();
        let body = if self.include_stack_trace {
            format!("{}: {}", err.message(), err.backtrace())
        } else {
            err.message().to_string()
        };
        Response::new(status).body(body)
    }
}

LegacyDataMigrator handles one-time data migration from old schema. Rarely accessed after initial migration.

struct LegacyDataMigrator {
    source_db: Connection,
    target_db: Connection,
    batch_size: usize,
}

impl LegacyDataMigrator {
    async fn migrate_users(&self) -> Result<usize> {
        let users = self.source_db.query("SELECT * FROM old_users").await?;
        self.target_db.insert_batch(&users).await
    }
}

BackupScheduler runs nightly database backups. Only accessed by cron jobs.

struct BackupScheduler {
    backup_path: PathBuf,
    retention_days: u32,
    compression: bool,
}

impl BackupScheduler {
    async fn run_backup(&self) -> Result<BackupResult> {
        let timestamp = Utc::now().format("%Y%m%d").to_string();
        let path = self.backup_path.join(format!("backup_{}.sql.gz", timestamp));
        self.db.dump_to_file(&path).await
    }
}

AuditLogArchiver moves old audit logs to cold storage. Runs monthly with minimal access.

struct AuditLogArchiver {
    archive_bucket: S3Bucket,
    retention_months: u32,
}

impl AuditLogArchiver {
    async fn archive_old_logs(&self) -> Result<usize> {
        let cutoff = Utc::now() - Duration::days(self.retention_months * 30);
        let logs = self.db.query("SELECT * FROM audit_logs WHERE created_at < ?", &[cutoff]).await?;
        self.archive_bucket.upload_batch(&logs).await
    }
}

SchemaVersionChecker validates database schema version on startup. Only accessed once per deployment.

struct SchemaVersionChecker {
    expected_version: String,
    migrations_path: PathBuf,
}

impl SchemaVersionChecker {
    async fn check(&self) -> Result<bool> {
        let current = self.db.query_one("SELECT version FROM schema_info").await?;
        Ok(current == self.expected_version)
    }
}

ReportGenerator creates monthly business reports. Only accessed by scheduled jobs.

struct ReportGenerator {
    templates: HashMap<String, Template>,
    output_format: OutputFormat,
}

impl ReportGenerator {
    async fn generate_monthly_report(&self, month: u32, year: u32) -> Result<Report> {
        let data = self.fetch_monthly_data(month, year).await?;
        let template = self.templates.get("monthly").unwrap();
        template.render(&data)
    }
}

FeatureFlagMigrator updates feature flag configurations. Only used during deployment.

struct FeatureFlagMigrator {
    flags_config: PathBuf,
    environment: String,
}

impl FeatureFlagMigrator {
    async fn apply_flags(&self) -> Result<()> {
        let config = load_config(&self.flags_config)?;
        for (flag, value) in config.flags {
            self.db.upsert("feature_flags", &flag, &value).await?;
        }
        Ok(())
    }
}

DatabaseIndexOptimizer analyzes and optimizes indexes. Runs weekly during maintenance window.

struct DatabaseIndexOptimizer {
    analyze_threshold: f64,
    reindex_threshold: f64,
}

impl DatabaseIndexOptimizer {
    async fn optimize(&self) -> Result<OptimizationReport> {
        let stats = self.db.query("SELECT * FROM pg_stat_user_indexes").await?;
        let mut reindexed = 0;
        for stat in stats {
            if stat.bloat_ratio > self.reindex_threshold {
                self.db.execute(&format!("REINDEX INDEX {}", stat.index_name)).await?;
                reindexed += 1;
            }
        }
        Ok(OptimizationReport { reindexed })
    }
}

EmailTemplateLoader loads email templates from disk. Only accessed when sending specific email types.

struct EmailTemplateLoader {
    templates_dir: PathBuf,
    cache: HashMap<String, Template>,
}

impl EmailTemplateLoader {
    fn load(&self, name: &str) -> Result<Template> {
        if let Some(t) = self.cache.get(name) {
            return Ok(t.clone());
        }
        let path = self.templates_dir.join(format!("{}.html", name));
        let content = fs::read_to_string(&path)?;
        Ok(Template::parse(&content)?)
    }
}
